import { LitElement, html } from "lit";
import { customElement, property } from "lit/decorators.js";
import { adoptLightStyles } from "../light-dom/light-dom.js";

/**
 * `<lv-textarea>`: a token-styled multi-line text input.
 *
 * Same data-down/events-up contract as `<lv-input>`: value in via the property, bubbling
 * `lv-input` event out on change; the wire's `l:model` owns the binding. Sets `aria-invalid`
 * from the `invalid` flag (WAI-ARIA, research 4.3). Owned source, copied in by
 * `lievit add textarea`. Light-DOM rendered.
 */
@customElement("lv-textarea")
export class LvTextarea extends LitElement {
  /** Current text value (data down). */
  @property() value = "";

  /** Placeholder shown when empty. */
  @property() placeholder = "";

  /** Visible rows. */
  @property({ type: Number }) rows = 3;

  /** Marks the field invalid: red border plus `aria-invalid`. */
  @property({ type: Boolean }) invalid = false;

  /** Disables the control. */
  @property({ type: Boolean }) disabled = false;

  createRenderRoot(): this {
    adoptLightStyles("lv-textarea", LvTextarea.css);
    return this;
  }

  static readonly css = `
    .lv-textarea {
      font-family: var(--lv-font-sans);
      font-size: var(--lv-text-base);
      line-height: var(--lv-leading);
      color: var(--lv-color-fg);
      background: var(--lv-color-bg);
      padding: var(--lv-space-2) var(--lv-space-3);
      border: 1px solid var(--lv-color-border);
      border-radius: var(--lv-radius-sm);
      width: 100%;
      box-sizing: border-box;
      resize: vertical;
    }
    .lv-textarea:focus-visible { outline: none; box-shadow: var(--lv-ring); }
    .lv-textarea--invalid { border-color: var(--lv-color-danger); }
    .lv-textarea[disabled] { opacity: 0.5; cursor: not-allowed; }
  `;

  private onInput(e: Event) {
    const value = (e.target as HTMLTextAreaElement).value;
    this.value = value;
    this.dispatchEvent(
      new CustomEvent("lv-input", { detail: value, bubbles: true, composed: true })
    );
  }

  render() {
    return html`
      <textarea
        class="lv-textarea ${this.invalid ? "lv-textarea--invalid" : ""}"
        rows=${this.rows}
        placeholder=${this.placeholder}
        ?disabled=${this.disabled}
        aria-invalid=${this.invalid ? "true" : "false"}
        .value=${this.value}
        @input=${this.onInput}
      ></textarea>
    `;
  }
}

declare global {
  interface HTMLElementTagNameMap {
    "lv-textarea": LvTextarea;
  }
}

/*
 * Copyright 2026 Francesco Bilotta
 * Licensed under the Apache License, Version 2.0 (the "License").
 *
 * lievit-ui design tokens. Copied into the adopter's project by `lievit add <component>`
 * (first run only; merged on re-run). Components reference these by CSS custom property
 * name, never by hardcoded value, so a retheme is a token override in :root, not a
 * component edit (ADR-0005, ADR-0009).
 *
 * The --lv-* prefix is load-bearing: lievit-ui co-exists with the adopter's own CSS and
 * with Tailwind's generated vars, so the namespace prevents collisions (research 4.2).
 *
 * v0.1 ships a single :root swatch (no dark mode). The structure leaves room for a future
 * `@media (prefers-color-scheme: dark)` block without a breaking change (research 5.2).
 */
:root {
  /* color: base surfaces and text */
  --lv-color-bg: #ffffff;
  --lv-color-fg: #111827;
  --lv-color-surface: #f9fafb; /* table row zebra, card background (research 4.2) */
  --lv-color-border: #d1d5db;
  --lv-color-muted: #6b7280;

  /* color: brand */
  --lv-color-primary: #2563eb;
  --lv-color-primary-fg: #ffffff;

  /* color: status (gestionale completeness, research 4.2) */
  --lv-color-success: #16a34a;
  --lv-color-success-fg: #ffffff;
  --lv-color-warning: #d97706;
  --lv-color-warning-fg: #ffffff;
  --lv-color-info: #2563eb; /* aliases primary; kept distinct so a retheme can split them */
  --lv-color-info-fg: #ffffff;
  --lv-color-danger: #dc2626;
  --lv-color-danger-fg: #ffffff;

  /* spacing (4px scale) */
  --lv-space-1: 0.25rem;
  --lv-space-2: 0.5rem;
  --lv-space-3: 0.75rem;
  --lv-space-4: 1rem;
  --lv-space-5: 1.25rem;
  --lv-space-6: 1.5rem;

  /* radius */
  --lv-radius-sm: 0.25rem;
  --lv-radius-md: 0.5rem;

  /* type */
  --lv-font-sans: system-ui, -apple-system, "Segoe UI", Roboto, sans-serif;
  --lv-text-sm: 0.875rem;
  --lv-text-base: 1rem;
  --lv-text-lg: 1.125rem;
  --lv-leading: 1.5;

  /* elevation (gestionale completeness, research 4.2) */
  --lv-shadow-sm: 0 1px 2px 0 rgb(0 0 0 / 0.05);
  --lv-shadow-md: 0 4px 6px -1px rgb(0 0 0 / 0.07);

  /* focus ring: shared by every interactive primitive */
  --lv-ring: 0 0 0 3px color-mix(in srgb, var(--lv-color-primary) 35%, transparent);
}
